"use client";

import { useState, useEffect } from "react";
import { Card, Title, Text } from "@tremor/react";
import toast from "react-hot-toast";
import { ClientSelector } from "./client-selector";
import { HookConfiguration } from "./hook-configuration";
import { QuerySettings } from "./query-settings";
import { InstallInstructions } from "./install-instructions";
import { LimitedAutomationNotice } from "./limited-automation-notice";
import { SessionStatus } from "./session-status";

type Client = "claude-code" | "cursor" | "continue" | "windsurf" | "codex" | "custom";

interface AutomationSettings {
  client: Client;
  autoInjectContext: boolean;
  trackAccessedFiles: boolean;
  preserveOnCompaction: boolean;
  restoreOnSessionStart: boolean;
  enrichPrompts: boolean;
  maxTokensPerQuery: number;
  searchMode: "keyword" | "semantic" | "hybrid";
  includeSummaries: boolean;
}

const CLIENTS_WITH_HOOKS: Client[] = ["claude-code"];

export function AutomationSettingsPanel({ projectId, apiKey }: Props) {
  const [settings, setSettings] = useState<AutomationSettings | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const hasHookSupport = settings && CLIENTS_WITH_HOOKS.includes(settings.client);

  // Fetch settings on mount
  useEffect(() => { /* ... */ }, [projectId]);

  // Save handler
  const handleSave = async () => { /* ... */ };

  if (isLoading) {
    return <Card><div className="loading loading-spinner" /></Card>;
  }

  return (
    <div className="space-y-6">
      {/* Step 1: Client Selection */}
      <Card>
        <Title>Step 1: Select Your Client</Title>
        <ClientSelector
          selected={settings.client}
          onChange={(client) => setSettings({ ...settings, client })}
        />
      </Card>

      {/* Step 2: Configuration */}
      <Card>
        <Title>Step 2: Configure Automation</Title>
        {hasHookSupport ? (
          <>
            <HookConfiguration settings={settings} onChange={setSettings} />
            <QuerySettings settings={settings} onChange={setSettings} />
          </>
        ) : (
          <LimitedAutomationNotice client={settings.client} />
        )}
      </Card>

      {/* Step 3: Install */}
      <Card>
        <Title>Step 3: Install Configuration</Title>
        <InstallInstructions
          projectId={projectId}
          apiKey={apiKey}
          settings={settings}
          hasHookSupport={hasHookSupport}
        />
      </Card>

      {/* Session Status */}
      <Card>
        <Title>Session Status</Title>
        <SessionStatus projectId={projectId} />
      </Card>

      {/* Save Button */}
      <div className="flex justify-end">
        <button
          className={`btn btn-primary ${isSaving ? "loading" : ""}`}
          onClick={handleSave}
          disabled={isSaving}
        >
          {isSaving ? "Saving..." : "Save Settings"}
        </button>
      </div>
    </div>
  );
}
```
